insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:2-5-2-why-performers-should-not-use-peds:exam:a5a55589', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is a sporting sanction a performer could face for using PEDs?", "options": ["A guaranteed improvement in their long-term physical fitness levels", "Being banned from competition and stripped of any titles they won", "An automatic invitation to compete at the next major international event", "A permanent increase in the size of their sponsorship deals"], "hint": "Think about what actually happens to someone caught using a banned substance, not what a performer might hope for.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being banned from competition and stripped of any titles they won.</strong></p>\n<ul>\n<li>Bans, fines and stripped titles/medals are real sanctions for PED use.</li>\n<li>The other options describe rewards, which would never follow a positive test.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:fb37b77d', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "A performer has used PEDs for over a year. Which of these is most likely to be a LONG-TERM effect of that use?", "options": ["A single restless night before an important competition", "Lasting damage to the heart, liver or kidneys, and disrupted hormones", "Feeling nervous just before stepping out to compete", "A short burst of extra confidence and energy lasting only for one single afternoon"]}'::jsonb, '{"answer": 1, "explain": "Sustained use over months or years is what causes lasting organ damage and hormone disruption. The other options describe brief, one-off feelings, not lasting harm."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:1790adff', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "A sprinter says, ''It''s not cheating if it just helps me train harder.'' Why is this argument wrong?", "options": ["Because using PEDs gives an advantage a clean rival cannot fairly match, so it is cheating", "Because sprinters are never actually tested for banned substances at all", "Because training harder is always against the rules of every sport", "Because only substances that are completely legal to buy in an ordinary shop count as cheating"]}'::jsonb, '{"answer": 0, "explain": "Whatever a performer''s intention, PEDs create an advantage a clean rival has not agreed to and cannot match through training alone — that is what makes it cheating."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:78ab29d9', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "Which statement correctly links PED use to the law, not just to sporting rules?", "options": ["PEDs are always freely and completely legally available from any high-street pharmacy", "Many PEDs are controlled substances, so using them can also be a criminal matter", "Sporting rules and UK law always say exactly the same thing about PEDs", "The law only applies to performers who compete at international level"]}'::jsonb, '{"answer": 1, "explain": "Because many PEDs are controlled substances, a performer can face criminal consequences on top of sporting ones — sporting rules and the law are separate but can both apply."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:1f4f7894', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "A performer is found to have used PEDs during a competition they won. What is a likely sporting sanction?", "options": ["An official warning with absolutely no other consequence attached to it", "Being stripped of the title or medal, alongside a ban and possibly a fine", "A guaranteed place in the following year''s national training squad", "A formal invitation to become an ambassador for the sport''s governing body"]}'::jsonb, '{"answer": 1, "explain": "Stripping the title or medal, a ban and a fine are the standard sporting sanctions — the other options describe rewards, which would never follow a positive test."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:82ad5dc3', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "Why might a positive PED test damage a performer''s career even after any ban ends?", "options": ["Because governing bodies automatically double every performer''s future funding", "Because sponsors and fans may permanently lose trust, costing income and reputation", "Because a ban legally prevents the performer from ever training again", "Because the media are legally required by law to permanently stop reporting on that performer"]}'::jsonb, '{"answer": 1, "explain": "Lost sponsorship, income and public trust can outlast the ban itself — reputational damage is often the longer-lasting consequence, not a legal block on training."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:mcq:60e61b82', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'mcq', 'mcq', 1, '{"question": "A youth coach says PEDs are ''a private choice that only affects the performer using them.'' Why is this misleading?", "options": ["Because young fans may copy the behaviour of performers they admire", "Because it is completely accurate and no one else is ever affected by it", "Because only coaches, and never fans, are influenced by a performer''s choices", "Because private choices are never relevant to any sporting rules whatsoever"]}'::jsonb, '{"answer": 0, "explain": "Elite performers are watched and copied, especially by young fans, so a ''private'' choice to use PEDs can spread its influence well beyond the performer themselves."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:8fc7c008', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "PEDs can cause serious health problems that only appear years after a performer stops using them."}'::jsonb, '{"answer": true, "explain": "Long-term damage to organs and hormone balance can build up over time and can outlast the period of use — the risk does not simply end when the substance stops."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:b0db96b1', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "Using PEDs is only a genuine problem if a performer actually gets caught by a drugs test."}'::jsonb, '{"answer": false, "explain": "The health risks and the unfair advantage both exist whether or not a performer is ever tested — getting caught only adds sporting and legal consequences on top."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:3d2f172a', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "PED use can break UK law as well as the rules of a sport."}'::jsonb, '{"answer": true, "explain": "Many PEDs are controlled substances, so possessing, using or supplying them can be a criminal matter in addition to a breach of sporting rules."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:9b08e88c', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "A performer who is banned for using PEDs usually keeps any medals they won while using the substance."}'::jsonb, '{"answer": false, "explain": "Sanctions typically include being stripped of titles or medals won while using the substance, alongside a ban and possibly a fine."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:17443189', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "Losing sponsorship deals is a realistic risk for a performer whose PED use becomes public."}'::jsonb, '{"answer": true, "explain": "A positive test is usually made public, and sponsors can withdraw support once trust with fans and the public is damaged."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tf:e392629a', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tf', 'tf', 1, '{"question": "Whether a performer is seen as a role model has nothing to do with whether they should use PEDs."}'::jsonb, '{"answer": false, "explain": "It is directly relevant — young fans often copy the choices of performers they admire, so a performer''s decision can influence people beyond themselves."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:learn:9a1ea5c9', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "The health risks of using PEDs", "reading": "<h4>Short-term effects</h4>\n<ul>\n<li>Even a short course of PEDs can bring on sudden mood swings, aggression, disturbed sleep and a higher risk of injury from training harder than the body is ready for.</li>\n<li>Some substances put an immediate strain on the heart and liver as the body tries to cope with them.</li>\n</ul>\n<h4>Long-term effects</h4>\n<ul>\n<li>Months or years of use can leave lasting damage to the heart, liver and kidneys, and can upset the body''s normal hormone balance.</li>\n<li>Some of this damage does not reverse once a performer stops using the substance — the risk does not end when the use does.</li>\n</ul>\n<h4>Why this matters for the exam</h4>\n<ul>\n<li>A vague line such as \"it damages your body\" earns little. Naming a <strong>short-term</strong> effect and a separate <strong>long-term</strong> one shows the depth an examiner is looking for.</li>\n</ul>", "question": "Which of these is best described as a LONG-TERM health risk of using PEDs, rather than a short-term one?", "options": ["Feeling unusually irritable during the very first week or two of starting the substance", "Lasting damage to organs such as the heart, liver or kidneys after months of use", "A single night of poor sleep straight after an evening training session", "A sudden mood swing that a training partner happens to notice"]}'::jsonb, '{"answer": 1, "explain": "Organ damage and disrupted hormones typically build up over months or years of use, and can outlast the use itself — that makes it long-term, unlike a mood swing or one bad night''s sleep."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:learn:6306a259', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Why using PEDs is cheating — and often against the law", "reading": "<h4>Unfair on clean athletes</h4>\n<ul>\n<li>Sport is meant to test natural ability, training and skill. A performer who uses PEDs gains an advantage that a clean rival has not agreed to and cannot fairly match, however hard that rival trains.</li>\n<li>This is why using PEDs is <strong>cheating</strong>, not simply a risky personal choice — it can change who actually wins.</li>\n</ul>\n<h4>Against the rules of the sport</h4>\n<ul>\n<li>Every governing body bans PEDs in its own rules. Using them breaks those rules whether or not a performer is ever caught by a test.</li>\n</ul>\n<h4>Often against the law too</h4>\n<ul>\n<li>Many performance-enhancing substances are controlled under UK law, so possessing, using or supplying them can lead to criminal trouble as well as sporting trouble.</li>\n<li>A performer who uses PEDs can end up breaking two separate sets of rules at once: the sport''s own rules, and the law of the land.</li>\n</ul>", "question": "Why is using PEDs described as ''cheating'', rather than just a risky personal choice?", "options": ["Because it gives an advantage a clean rival has not agreed to and cannot fairly match", "Because every performer who tries it is caught by a drugs test within days", "Because it always costs a lot more money than training naturally without any banned substances", "Because coaches personally disapprove of it on moral grounds in every single case"]}'::jsonb, '{"answer": 0, "explain": "The advantage is unearned and cannot be matched by fair training, which is what turns it from a personal risk into cheating that affects the whole competition."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:learn:e18d596a', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "The fallout: sanctions, career and being a role model", "reading": "<h4>Sporting sanctions</h4>\n<ul>\n<li>A performer caught using PEDs can be banned from competing, fined, and stripped of any titles or medals won while using the substance.</li>\n<li>A ban can end a career outright, especially for a performer whose competitive years are already limited.</li>\n</ul>\n<h4>Career and reputation</h4>\n<ul>\n<li>A positive test is usually made public, so a performer can lose sponsorship deals, income and the trust of fans and teammates — often for good.</li>\n</ul>\n<h4>Being a role model</h4>\n<ul>\n<li>Elite performers are watched and copied by young fans. A performer who uses PEDs risks teaching those fans that cheating is an acceptable shortcut to success.</li>\n</ul>", "question": "Why is ''being a role model'' a genuine reason for a performer not to use PEDs?", "options": ["Because role models are legally banned from ever taking part in competitive sport", "Because young fans may copy the choices they see successful performers make", "Because it has no real connection to a performer''s own personal decisions", "Because only performers who already have sponsorship deals count as role models"]}'::jsonb, '{"answer": 1, "explain": "Fans, especially young ones, often copy the behaviour of performers they look up to — so a performer''s choice to use PEDs can spread beyond their own career."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:misc:db24fa0a', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> PEDs are only a problem if you get caught — if nobody finds out, no real harm has been done.</p><p><strong>✅ The correct idea:</strong> Getting caught only adds sporting and legal consequences on top of harms that exist either way. The health risks happen to the performer''s own body regardless of any test result, and the unfair advantage over clean rivals exists the moment the substance is used, whether or not anyone ever finds out.</p>", "question": "What is wrong with the idea that PED use ''doesn''t matter unless you get caught''?", "options": ["Nothing at all — getting caught is genuinely the only real consequence that ever exists", "The health risks and unfair advantage exist regardless of whether anyone finds out", "Drugs tests are so accurate that every single user is always caught immediately", "Being caught actually removes all of the health risks a performer has taken"]}'::jsonb, '{"answer": 1, "explain": "The harm to the performer''s own health, and the unfair advantage over clean rivals, both exist the moment PEDs are used — detection only adds further consequences."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:misc:a68d2454', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using PEDs is basically the same as any other risky training method, such as training too hard.</p><p><strong>✅ The correct idea:</strong> Overtraining is risky, but it is not against the rules or the law, and it does not create an unearned advantage over rivals. PED use is different because it is a deliberate breach of a sport''s rules (and often the law), designed specifically to gain an edge a rival cannot fairly match — that combination is what makes it cheating, not just a training risk.</p>", "question": "How does PED use differ from a risky training method like overtraining?", "options": ["It doesn''t — the two carry exactly the same risks and consequences for a performer", "PED use deliberately breaks a sport''s rules (and often the law) to gain an unfair edge", "Overtraining is actually more strictly banned by governing bodies than PED use is", "Only PED use can ever possibly lead to any kind of physical injury occurring during training"]}'::jsonb, '{"answer": 1, "explain": "Overtraining is not a rule-break; PED use is a deliberate breach of the sport''s rules, and often the law, aimed at gaining an advantage rivals cannot fairly match."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:misc:0d3d68ee', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The only real consequence of using PEDs is being banned from competing.</p><p><strong>✅ The correct idea:</strong> A ban is just one of several consequences. A performer can also be fined, stripped of titles or medals, lose sponsorship and income, damage their reputation with fans for good, face legal trouble because many PEDs are controlled substances, and risk their own long-term health — a ban rarely stands alone.</p>", "question": "Besides a ban, which of these is also a realistic consequence of using PEDs?", "options": ["An automatic and guaranteed improvement in the performer''s public reputation", "Being fined, stripped of titles, and losing sponsorship income", "A guaranteed place on the national governing body''s board", "Permanent removal of every health risk the substance caused"]}'::jsonb, '{"answer": 1, "explain": "Fines, stripped titles and lost sponsorship commonly accompany a ban — reputation, legal and health consequences can follow too, so a ban is rarely the only outcome."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tips:ec0a882c', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words and mark tariffs for this topic", "reading": "<p>Questions on why performers should not use PEDs are set at every level of demand:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name a reason. \"Identify one reason performers should not use PEDs [1]\" wants a single named reason, nothing more.</li>\n<li><strong>Explain</strong> — give a reason plus a \"because\". \"Explain why PED use is considered cheating [2]\" wants the idea (unfair advantage) plus why that makes it cheating.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh both sides of an issue and reach a justified judgement. These carry the highest tariffs (6 or 8 marks) and appear in Sections B and C.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to a scenario; [8] in Section C wants balance and a judgement, not a list.</p>", "question": "A question says: ''Explain one reason why performers should not use PEDs [2]''. What earns full marks?", "options": ["Naming as many reasons as possible without any explanation", "A named reason plus a linked ''because'' that develops it", "A single word with no further detail at all", "A long list of every sanction a performer could ever face"]}'::jsonb, '{"answer": 1, "explain": "''Explain'' plus [2] wants a reason developed with a reason why — a bare list, a single word, or an undeveloped list of sanctions would not reach both marks."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tips:c2dcb4bb', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Building a balanced Discuss / Evaluate answer", "reading": "<p>The 8-mark question on this topic usually asks you to weigh the risks of PED use against any possible gains, then reach a judgement. Use this shape:</p>\n<ul>\n<li>Give a risk (health, cheating, sanctions, career) and explain why it matters.</li>\n<li>Acknowledge a possible gain a performer might hope for (better performance, faster results), so your answer is balanced, not one-sided.</li>\n<li>Weigh them against each other, then commit to a judgement — don''t just describe both sides and stop.</li>\n</ul>\n<p><strong>Three sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One serious risk of using PEDs is… because…\"</li>\n<li>\"However, some performers might feel the possible gain of… is worth it because…\"</li>\n<li>\"Overall, the risks outweigh the gains because…\"</li>\n</ul>", "question": "Why should a Discuss / Evaluate answer on this topic mention a possible gain, not only the risks?", "options": ["It shouldn''t — only listing risks ever earns any marks at all", "Acknowledging both sides shows the balance a top-band answer needs", "Gains are always more important to mention than any of the risks", "Mentioning gains is required only in Section A multiple-choice questions"]}'::jsonb, '{"answer": 1, "explain": "Top-band levelled answers are balanced — they weigh a possible gain against the risks before reaching a judgement, rather than only listing one side."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:tips:cad93d53', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic shows up across the paper", "reading": "<p><strong>Where it shows up:</strong> quick recall in <strong>Section A</strong> (identify/state a reason, or a single mark-scheme fact about sanctions); applied Explain questions in <strong>Section B</strong>, often built around a named performer in a scenario; and the topic feeds naturally into a <strong>Section C</strong> Discuss/Evaluate question weighing risks against gains.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six reasons in pairs: health (short/long term), fairness/rules, and consequences (sanctions and reputation).</li>\n<li>In Section B, always link your reason to the named performer or scenario in front of you — a general answer is capped.</li>\n<li>For the 8-mark answer, keep one risk in reserve as your \"however\" point so you never run out of balance.</li>\n</ul>", "question": "In a Section B scenario about a named performer, your explanation should be linked to...", "options": ["a completely different sport you happen to prefer", "the named performer and details in the scenario given", "a famous athlete not mentioned anywhere in the question", "your own personal opinion of that sport in general"]}'::jsonb, '{"answer": 1, "explain": "Section B rewards application — using the scenario''s own details. A general answer that ignores the named performer is capped below full marks."}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:fib:2af28f59', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'fib', 'fib', 1, '{"question": "Using PEDs can cause serious _____ risks, both straight away and years later.", "blankOptions": {"B1": ["cheating", "law", "copy", "health"]}}'::jsonb, '{"blanks": {"B1": "health"}}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:fib:d15cf6e9', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'fib', 'fib', 1, '{"question": "PED use is a form of _____ because it creates an advantage a clean rival cannot fairly match.", "blankOptions": {"B1": ["cheating", "health", "copy", "banned"]}}'::jsonb, '{"blanks": {"B1": "cheating"}}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:fib:de614988', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'fib', 'fib', 1, '{"question": "Many PEDs are controlled substances, so using them can break the _____ as well as the rules of the sport.", "blankOptions": {"B1": ["banned", "copy", "law", "cheating"]}}'::jsonb, '{"blanks": {"B1": "law"}}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:fib:c9aac078', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'fib', 'fib', 1, '{"question": "A performer caught using PEDs can be _____ from competition and lose any titles they won.", "blankOptions": {"B1": ["cheating", "health", "banned", "law"]}}'::jsonb, '{"blanks": {"B1": "banned"}}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:fib:584b56d6', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'fib', 'fib', 1, '{"question": "Elite performers are role models, so young fans may _____ risky choices they see them make.", "blankOptions": {"B1": ["cheating", "copy", "law", "banned"]}}'::jsonb, '{"blanks": {"B1": "copy"}}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:dd32a0ab', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Short-term health risk”?", "options": ["Going against a sport''s own ban on banned substances, and often UK law on controlled substances too", "A ban, a fine or the loss of a title or medal given to someone caught using a banned substance", "Lasting damage to organs and disrupted hormones that can follow months or years of use", "Mood swings, poor sleep and raised injury risk that can appear within days of starting to use a substance"]}'::jsonb, '{"answer": 3, "explain": "“Short-term health risk” means: Mood swings, poor sleep and raised injury risk that can appear within days of starting to use a substance"}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:da7a5d63', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Long-term health risk”?", "options": ["Gaining an advantage that a clean rival has not agreed to and cannot fairly match", "The duty elite performers have, because young fans may copy the choices they see them make", "Lasting damage to organs and disrupted hormones that can follow months or years of use", "A ban, a fine or the loss of a title or medal given to someone caught using a banned substance"]}'::jsonb, '{"answer": 2, "explain": "“Long-term health risk” means: Lasting damage to organs and disrupted hormones that can follow months or years of use"}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:c51fbc68', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cheating”?", "options": ["A ban, a fine or the loss of a title or medal given to someone caught using a banned substance", "Gaining an advantage that a clean rival has not agreed to and cannot fairly match", "Lasting damage to organs and disrupted hormones that can follow months or years of use", "Mood swings, poor sleep and raised injury risk that can appear within days of starting to use a substance"]}'::jsonb, '{"answer": 1, "explain": "“Cheating” means: Gaining an advantage that a clean rival has not agreed to and cannot fairly match"}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:20f11c9a', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Breaking the rules”?", "options": ["Gaining an advantage that a clean rival has not agreed to and cannot fairly match", "Mood swings, poor sleep and raised injury risk that can appear within days of starting to use a substance", "Lasting damage to organs and disrupted hormones that can follow months or years of use", "Going against a sport''s own ban on banned substances, and often UK law on controlled substances too"]}'::jsonb, '{"answer": 3, "explain": "“Breaking the rules” means: Going against a sport''s own ban on banned substances, and often UK law on controlled substances too"}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:c34e1ad3', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sporting sanction”?", "options": ["Lasting damage to organs and disrupted hormones that can follow months or years of use", "Mood swings, poor sleep and raised injury risk that can appear within days of starting to use a substance", "Going against a sport''s own ban on banned substances, and often UK law on controlled substances too", "A ban, a fine or the loss of a title or medal given to someone caught using a banned substance"]}'::jsonb, '{"answer": 3, "explain": "“Sporting sanction” means: A ban, a fine or the loss of a title or medal given to someone caught using a banned substance"}'::jsonb),
('sport-studies:2-5-2-why-performers-should-not-use-peds:match:17c1992e', 'sport-studies', 'sport-studies:2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Role-model responsibility”?", "options": ["A ban, a fine or the loss of a title or medal given to someone caught using a banned substance", "Gaining an advantage that a clean rival has not agreed to and cannot fairly match", "The duty elite performers have, because young fans may copy the choices they see them make", "Lasting damage to organs and disrupted hormones that can follow months or years of use"]}'::jsonb, '{"answer": 2, "explain": "“Role-model responsibility” means: The duty elite performers have, because young fans may copy the choices they see them make"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:exam:29cc4f29', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best describes the Whereabouts Rule?", "options": ["Athletes must report their daily location so testers can carry out an unannounced test at any time", "Athletes must only ever compete in sporting events held within their own home country each season", "Athletes must publish their full training diet in complete detail on a public social media account", "Athletes must retire from all competition once they reach a certain fixed age"], "hint": "Think about why testers need to know where an athlete will be, even outside of competition.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1)</h5>\n<p><strong>Answer: A — Athletes must report their daily location so testers can carry out an unannounced test at any time.</strong></p>\n<ul>\n<li>This is the purpose of the Whereabouts Rule — allowing testing outside of competition, not only at events.</li>\n<li>The other options describe unrelated ideas (country of competition, diet publishing, retirement age).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:7b913ce0', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "What does WADA stand for and what is its overall aim?", "options": ["The World Athletics Development Association, a group that funds new stadium construction projects", "The World Anti-Doping Agency, an international body aiming to detect and deter PED use", "The Worldwide Amateur Draft Assembly, a body that selects amateur athletes for professional contracts", "The World Athletic Data Analysts, a company that publishes statistics after major events"]}'::jsonb, '{"answer": 1, "explain": "WADA is the World Anti-Doping Agency — its job is detecting and deterring doping, not stadium funding, drafting amateurs, or publishing statistics."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:13c2c764', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "An athlete in a WADA testing pool must give anti-doping authorities their daily whereabouts. Why?", "options": ["So that a specific supporters'' club can arrange to meet the athlete after every home match", "So the athlete''s diet can be planned in advance by a national governing body nutritionist", "So an unannounced test can be carried out at any time, including outside of competition", "So travel journalists can accurately report an athlete''s holiday plans to the public"]}'::jsonb, '{"answer": 2, "explain": "The Whereabouts Rule exists so an unannounced test can reach the athlete at any time — not to help a supporters'' club, a nutritionist, or journalists."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:085a9064', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of an out-of-competition (random) test?", "options": ["Officials test the reigning winning finalist immediately after the final whistle of a major championship", "Officials interview a retired athlete about their career for a televised documentary", "Officials measure the size of a stadium pitch before a scheduled international fixture", "Officials test a sprinter unannounced during a routine training session in the off-season"]}'::jsonb, '{"answer": 3, "explain": "Out-of-competition testing happens away from events, unannounced — such as during off-season training — not at a final, an interview, or a pitch measurement."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:39cfa2e3', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "What can a blood test detect that a urine test alone often struggles to pick up?", "options": ["Blood doping, such as artificially boosting the number of red blood cells in circulation", "The exact brand and colour of the trainers an athlete happened to be wearing during a specific event", "How many hours of sleep an athlete had the night before a scheduled competition day", "The total number of spectators who attended a stadium on any single competition day"]}'::jsonb, '{"answer": 0, "explain": "Blood samples can reveal blood doping and an athlete''s blood values — trainers, sleep and attendance figures are not things a drugs test detects."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:e41377c4', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "A drugs test never finds a banned substance, but an athlete''s blood values change sharply over several tests. What does the biological passport do with this pattern?", "options": ["Ignores it completely and permanently, because only a single positive sample is ever treated as valid evidence", "Flags it as suspicious, because it compares the athlete against their own normal readings over time", "Automatically bans the athlete''s entire national team from the next major competition", "Deletes the athlete''s testing history so a fresh profile can be started from zero"]}'::jsonb, '{"answer": 1, "explain": "The passport flags a suspicious change from an athlete''s own normal pattern — it does not ignore the data, ban a whole team, or wipe the history."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:mcq:ed8fd98d', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'mcq', 'mcq', 1, '{"question": "Which statement about missing scheduled anti-doping tests is correct?", "options": ["Missing a test has absolutely no consequences at all as long as the athlete formally apologises to the testers afterwards", "Missing a test only matters if it happens during the same week as a major international final", "A pattern of missed tests or filing failures can be treated as a violation, even without a positive sample", "Missing a test simply moves the athlete to the very back of the queue for their next scheduled test"]}'::jsonb, '{"answer": 2, "explain": "Persistently missing tests or filing whereabouts incorrectly can itself count as a violation — it is not harmless, timing-dependent, or just a queuing issue."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:8293755a', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "WADA sets shared global anti-doping rules so that testing standards are consistent across countries."}'::jsonb, '{"answer": true, "explain": "That''s WADA''s core purpose — a single global standard rather than each nation policing itself differently."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:e077b7f2', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "The Whereabouts Rule only applies to athletes during the week of a major competition."}'::jsonb, '{"answer": false, "explain": "It applies all year round, including training and the off-season — catching doping that happens away from events is the whole point."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:0c735882', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "An athlete can only be sanctioned if a banned substance is actually found in one of their samples."}'::jsonb, '{"answer": false, "explain": "Persistently missing tests or filing whereabouts incorrectly can itself count as a violation, even with no positive sample."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:2e02d538', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "Out-of-competition testing means testers can arrive unannounced during an athlete''s normal training."}'::jsonb, '{"answer": true, "explain": "That is exactly what random, out-of-competition testing means — it is not limited to competition day."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:684f92ac', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "The biological passport compares an athlete against a fixed national average rather than their own readings."}'::jsonb, '{"answer": false, "explain": "It compares an athlete against their OWN normal pattern built up over time, not a shared national average."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tf:62d32eb4', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tf', 'tf', 1, '{"question": "Blood tests can reveal doping methods, such as artificially boosting red blood cells, that urine tests alone may miss."}'::jsonb, '{"answer": true, "explain": "Blood samples can show blood doping and an athlete''s blood values in ways urine testing struggles to match."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:learn:3c77bff5', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'learn', 'mcq', 1, '{"readingTitle": "What WADA is and does", "reading": "<h4>The idea</h4>\n<ul>\n<li><strong>WADA</strong> (the World Anti-Doping Agency) is the international organisation that leads the global fight against performance-enhancing drug (PED) use in sport.</li>\n<li>It sets and coordinates a shared set of anti-doping rules and testing standards, so every country and every sport works to the same expectations instead of each nation policing itself differently.</li>\n</ul>\n<h4>What WADA actually does</h4>\n<ul>\n<li>It keeps and reviews the list of substances and methods that are banned, updating it as new PEDs appear.</li>\n<li>It works with national anti-doping organisations and national governing bodies (NGBs), who carry out much of the day-to-day testing on its behalf.</li>\n<li>It funds and promotes research into new detection methods, so doping techniques do not stay ahead of testing.</li>\n<li>Its overall aim is to protect fair competition and protect athletes'' health by detecting, deterring and eventually eradicating PED use.</li>\n</ul>\n<h4>Why a single global body is needed</h4>\n<ul>\n<li>Before a shared system existed, some countries tested rigorously and others barely tested at all, so athletes were not competing on a level playing field.</li>\n<li>One set of rules, applied everywhere, means an athlete cannot simply rely on weaker testing elsewhere to avoid being caught.</li>\n</ul>", "question": "What is WADA''s main purpose in world sport?", "options": ["To act as the single television broadcaster for every major international sporting competition", "To set shared global anti-doping rules and drive the detection and deterrence of PED use", "To train elite athletes and coach national teams ahead of the Olympic Games", "To design new sports equipment that improves athletic performance in competition"]}'::jsonb, '{"answer": 1, "explain": "WADA is the international body that sets global rules and coordinates testing to detect and deter doping — not a broadcaster, a coaching body, or an equipment designer."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:learn:67f545ff', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'learn', 'mcq', 1, '{"readingTitle": "The Whereabouts Rule", "reading": "<h4>The idea</h4>\n<ul>\n<li>The <strong>Whereabouts Rule</strong> requires athletes in a registered testing pool to tell anti-doping authorities where they will be, every day, so testers can find them for a test at any time — not only on competition days.</li>\n<li>Athletes typically give their regular schedule for the coming months, plus one specific time slot each day when they guarantee they will be at a stated location and available for testing.</li>\n</ul>\n<h4>Why it exists</h4>\n<ul>\n<li>Most doping happens away from competition — during training, in the off-season — when an athlete might assume nobody is watching. The rule allows genuinely <strong>unannounced, out-of-competition testing</strong> at any point in the year.</li>\n<li>Without it, an athlete could avoid every test at an event, dope during training, and let the substance clear their system before the next competition.</li>\n</ul>\n<h4>What counts as a violation</h4>\n<ul>\n<li>An athlete does not need to fail a drugs test to be sanctioned. Persistently filing inaccurate whereabouts information, or missing tests, can itself be treated as an anti-doping rule violation.</li>\n<li>This is why elite athletes take the paperwork seriously — a pattern of missed tests can damage a career even without a single positive sample.</li>\n</ul>", "question": "Why does the Whereabouts Rule require athletes to give a daily location and time slot?", "options": ["So that testers can carry out an unannounced test at any point in the year, not just at events", "So that coaches always know exactly where their athletes are staying during a competition week", "So that ticket sales for major stadium events can be planned around athlete travel", "So that sponsors can arrange promotional photos with athletes at short notice"]}'::jsonb, '{"answer": 0, "explain": "The rule exists so testers can reach an athlete for a genuinely unannounced test out of competition — not to help coaches, ticketing or sponsors."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:learn:eb9a59fd', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'learn', 'mcq', 1, '{"readingTitle": "Testing methods", "reading": "<h4>The two main sample types</h4>\n<ul>\n<li><strong>Urine tests</strong> — the athlete provides a urine sample, analysed in a laboratory for banned substances or the products they break down into.</li>\n<li><strong>Blood tests</strong> — a blood sample can reveal doping methods urine testing struggles to detect, such as blood doping (artificially boosting red blood cells), and shows an athlete''s blood values.</li>\n</ul>\n<h4>When testing happens</h4>\n<ul>\n<li>Testing is not limited to competition day. <strong>Out-of-competition (random) testing</strong> means officials can turn up unannounced during training, in the off-season, or away from any event — exactly what the Whereabouts Rule makes possible.</li>\n<li>Random, unannounced testing matters because it removes an athlete''s ability to time their doping around when they expect to be tested.</li>\n</ul>\n<h4>The biological passport</h4>\n<ul>\n<li>Instead of judging one sample in isolation, the <strong>biological passport</strong> builds an athlete''s own individual profile of blood and urine readings over months and years.</li>\n<li>A sudden, unusual change away from an athlete''s own normal pattern can flag possible doping — even if the specific banned substance is never directly found in a sample.</li>\n<li>This matters because dopers cannot simply avoid one substance being detected; a suspicious pattern across many tests over time is itself evidence.</li>\n</ul>", "question": "What makes the biological passport a different approach from a single drugs test?", "options": ["It tracks an athlete''s own readings over time and flags unusual changes from their normal pattern", "It replaces every single urine and blood sample with one large photograph taken at the finish line of the race", "It only ever tests athletes once, on the very last day of their competitive career", "It is used exclusively to check the size and weight of an athlete''s sports equipment"]}'::jsonb, '{"answer": 0, "explain": "The passport compares an athlete against their OWN normal pattern over time, rather than judging one isolated sample — unlike a single test, a photograph, or equipment checks."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:misc:90eadc0f', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> WADA is basically just one laboratory that tests urine samples.</p><p><strong>✅ The correct idea:</strong> WADA is an international coordinating body — it sets the rules, standards and banned-substance list, while national anti-doping organisations and NGBs carry out much of the actual day-to-day testing on its behalf. It also funds research, not just processes samples.</p>", "question": "What does WADA itself mainly do, compared to national anti-doping organisations?", "options": ["It sets global rules and standards, while national bodies carry out much of the day-to-day testing", "It personally tests every single athlete in every single country using its own dedicated testing staff", "It only broadcasts televised doping scandals to a worldwide audience", "It only sells sports equipment approved for professional competition"]}'::jsonb, '{"answer": 0, "explain": "WADA sets the rules and standards; national anti-doping organisations and NGBs do most of the actual testing — WADA is not a broadcaster or an equipment seller."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:misc:0c112cc5', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Whereabouts Rule is only a paperwork formality with no real consequences.</p><p><strong>✅ The correct idea:</strong> Missing scheduled tests, or repeatedly filing inaccurate location information, can itself count as an anti-doping rule violation — treated seriously even if the athlete never actually failed a drugs test. Elite athletes take the reporting seriously because of this.</p>", "question": "What can happen to an athlete who repeatedly fails to file accurate whereabouts information?", "options": ["Nothing at all, because only a positive drugs test result can ever possibly lead to any kind of formal sanction", "They can be treated as having committed an anti-doping rule violation, even without a positive sample", "They automatically win their next competition without needing to attend at all", "Their national governing body is immediately replaced by a brand new organisation"]}'::jsonb, '{"answer": 1, "explain": "Repeated filing failures or missed tests can be treated as a violation in their own right, even with no positive sample — it is not consequence-free."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:misc:4191037d', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The biological passport only works by directly detecting a specific banned substance in a sample.</p><p><strong>✅ The correct idea:</strong> The biological passport can flag doping indirectly — by tracking an athlete''s own blood and urine readings over time and noticing a suspicious change from their normal pattern, even when no specific banned substance is ever found.</p>", "question": "How can the biological passport suggest doping without finding a banned substance?", "options": ["By comparing a single sample against a fixed international average reading taken from every other athlete", "By interviewing the athlete''s family, friends and former training partners about their habits", "By flagging an unusual change away from that athlete''s own normal pattern of readings over time", "By checking the make and model of the equipment the athlete used in competition"]}'::jsonb, '{"answer": 2, "explain": "The passport flags a change away from the athlete''s OWN pattern over time — it does not use a fixed average, interviews, or equipment checks."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tips:08f79f03', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>WADA questions range from quick recall to a full evaluation. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one testing method WADA-linked authorities use\" = one method, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what it is or how it works. \"Describe the Whereabouts Rule\" = explain what athletes must do.</li>\n<li><strong>Explain</strong> — give a reason, using \"because\". \"Explain why out-of-competition testing matters\" = the method plus why it closes a gap.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh up both sides and reach a judgement, used in the longer levelled questions.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]–[4] wants developed points or point+application; [6]/[8] levelled wants balanced analysis and a judgement.</p>", "question": "A question says ''Identify one testing method WADA uses [1]''. What is the safest answer?", "options": ["A long paragraph explaining the entire history of anti-doping testing", "One named testing method, such as blood testing or urine testing", "A list of every testing method you can possibly remember", "A description of a famous doping scandal from a past competition"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] wants exactly one named method. A long history, a full list, or a scandal description all waste time for a single mark."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tips:0a3fa03a', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: link the method to WHY it works", "reading": "<p>The most common way to lose marks here is naming a method without saying why it matters. Build every answer as <strong>method → what it catches → why that matters</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"WADA does blood tests.\"</li>\n<li><strong>✅ full marks:</strong> \"WADA-linked testers use blood tests because they can reveal blood doping, such as an artificial rise in red blood cells, which a urine test alone might miss.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named athlete or event). You must then apply a method to that scenario, not just describe it in general.</p>", "question": "In a Section B scenario about a named athlete, your answer about WADA''s methods should...", "options": ["ignore the scenario completely and describe any method in general terms", "apply a method to the specific detail given in the scenario", "only repeat the name of the athlete as many times as possible", "describe a completely different topic area instead"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the detail in the scenario, not ignoring it, repeating a name, or drifting off-topic."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:tips:b364937d', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where WADA appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> WADA''s role appears as quick recall in <strong>Section A</strong> (identify/describe a method or the Whereabouts Rule), as an applied point in <strong>Section B</strong> scenarios about a doping case, and can feed a <strong>Section C</strong> levelled answer discussing how effective anti-doping testing really is.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always link a testing method to what it can detect that another method might miss.</li>\n<li>Remember the Whereabouts Rule applies ALL year, not just on competition day.</li>\n<li>The biological passport is about a PATTERN over time, not a single sample — say so explicitly.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One method WADA-linked testers use is… because…\"</li>\n<li>\"This matters because it can catch doping that happens…\"</li>\n<li>\"However, a limitation of this method is…\"</li>\n</ul>", "question": "Why is it useful to say the biological passport tracks a PATTERN over time?", "options": ["It shows you understand it works differently from judging one single isolated sample", "It just fills up space in a longer answer without adding any real understanding at all to it", "It proves that no athlete has ever been caught doping in the history of sport", "It replaces the need to mention any testing method at all in your answer"]}'::jsonb, '{"answer": 0, "explain": "Naming the PATTERN-over-time idea shows real understanding of how the passport differs from a single test — it is not filler or a replacement for detail."}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:fib:4d0c3962', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'fib', 'fib', 1, '{"question": "WADA stands for the World Anti-Doping _____.", "blankOptions": {"B1": ["random", "doping", "Agency", "passport"]}}'::jsonb, '{"blanks": {"B1": "Agency"}}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:fib:5a5d64e7', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'fib', 'fib', 1, '{"question": "The Whereabouts Rule means athletes must report their daily _____ so testers can find them for a test.", "blankOptions": {"B1": ["random", "Agency", "location", "passport"]}}'::jsonb, '{"blanks": {"B1": "location"}}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:fib:9a8b0344', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'fib', 'fib', 1, '{"question": "Testing carried out unannounced during training, rather than only at an event, is called out-of-competition or _____ testing.", "blankOptions": {"B1": ["random", "doping", "passport", "Agency"]}}'::jsonb, '{"blanks": {"B1": "random"}}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:fib:4ce45745', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'fib', 'fib', 1, '{"question": "A blood test can help detect blood _____, such as an artificial rise in red blood cells.", "blankOptions": {"B1": ["location", "doping", "random", "passport"]}}'::jsonb, '{"blanks": {"B1": "doping"}}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:fib:13e7c928', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'fib', 'fib', 1, '{"question": "The biological _____ tracks an athlete''s own readings over time so any unusual change can be flagged.", "blankOptions": {"B1": ["random", "Agency", "passport", "doping"]}}'::jsonb, '{"blanks": {"B1": "passport"}}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:ee4280d2', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “WADA”?", "options": ["Testing-pool athletes must report their daily location so an unannounced test can happen at any time", "A sample that can reveal blood doping and show an athlete''s blood values", "The international body that sets rules to detect and deter PED use worldwide", "A profile that tracks an athlete''s own readings over time so unusual changes can be flagged"]}'::jsonb, '{"answer": 2, "explain": "“WADA” means: The international body that sets rules to detect and deter PED use worldwide"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:f816e10f', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Whereabouts Rule”?", "options": ["A profile that tracks an athlete''s own readings over time so unusual changes can be flagged", "Testing-pool athletes must report their daily location so an unannounced test can happen at any time", "The international body that sets rules to detect and deter PED use worldwide", "A sample that can reveal blood doping and show an athlete''s blood values"]}'::jsonb, '{"answer": 1, "explain": "“Whereabouts Rule” means: Testing-pool athletes must report their daily location so an unannounced test can happen at any time"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:99dfee98', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Urine test”?", "options": ["A sample analysed in a laboratory for banned substances or the products they break down into", "A sample that can reveal blood doping and show an athlete''s blood values", "Random, unannounced testing carried out during training or the off-season, not only at events", "Testing-pool athletes must report their daily location so an unannounced test can happen at any time"]}'::jsonb, '{"answer": 0, "explain": "“Urine test” means: A sample analysed in a laboratory for banned substances or the products they break down into"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:343c1423', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Blood test”?", "options": ["A sample analysed in a laboratory for banned substances or the products they break down into", "The international body that sets rules to detect and deter PED use worldwide", "Testing-pool athletes must report their daily location so an unannounced test can happen at any time", "A sample that can reveal blood doping and show an athlete''s blood values"]}'::jsonb, '{"answer": 3, "explain": "“Blood test” means: A sample that can reveal blood doping and show an athlete''s blood values"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:d1d804e5', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Out-of-competition testing”?", "options": ["A sample analysed in a laboratory for banned substances or the products they break down into", "Random, unannounced testing carried out during training or the off-season, not only at events", "A profile that tracks an athlete''s own readings over time so unusual changes can be flagged", "A sample that can reveal blood doping and show an athlete''s blood values"]}'::jsonb, '{"answer": 1, "explain": "“Out-of-competition testing” means: Random, unannounced testing carried out during training or the off-season, not only at events"}'::jsonb),
('sport-studies:2-5-3-the-role-of-wada:match:a8a0c4dc', 'sport-studies', 'sport-studies:2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Biological passport”?", "options": ["Random, unannounced testing carried out during training or the off-season, not only at events", "Testing-pool athletes must report their daily location so an unannounced test can happen at any time", "A profile that tracks an athlete''s own readings over time so unusual changes can be flagged", "The international body that sets rules to detect and deter PED use worldwide"]}'::jsonb, '{"answer": 2, "explain": "“Biological passport” means: A profile that tracks an athlete''s own readings over time so unusual changes can be flagged"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:exam:32bcc1ae', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'exam', 'mcq', 1, '{"num": "2", "question": "Which sanction removes an achievement a performer has already won, rather than affecting their future participation or finances?", "options": ["Being banned from competing for a set number of years", "Being stripped of a medal, title or record", "Being fined a sum of money set by the governing body", "Being required to attend an anti-doping education session"], "hint": "Think about which sanction targets something the performer already achieved, not something they might do or pay in future.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being stripped of a medal, title or record.</strong></p>\n<ul>\n<li>This sanction removes an achievement already gained, unlike a ban (future participation) or a fine (money).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:3767d775', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "What is most likely to happen to a performer caught using PEDs for a second time, having already served a ban once before?", "options": ["They receive an identical short suspension to a first-time offender in the same sport", "They may receive a lifetime ban, ending their career in that sport completely", "They are simply asked to apologise publicly with no further ban or fine applied", "They automatically become team captain for their club in the following season"]}'::jsonb, '{"answer": 1, "explain": "Repeat offenders face harsher sanctions than first-timers, and a lifetime ban is the most severe option available — the other outcomes describe no real sanction at all."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:f3af74cf', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "A performer is fined and stripped of a title after a positive drugs test. Which best explains why both sanctions are used together?", "options": ["One sanction removes their money, while the other removes their reputation and achievements", "The two sanctions cancel each other out, so the performer suffers no real consequence at all", "A fine and losing a title are simply two different names for exactly the same punishment", "Governing bodies choose a sanction completely at random with no consistent reasoning behind it"]}'::jsonb, '{"answer": 0, "explain": "A fine and being stripped of a title punish different things — money and reputation/achievement — which is why governing bodies often apply more than one sanction."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:f860b5b7', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "Why might a governing body strip a performer of a record they set, rather than only banning them from future competition?", "options": ["Because it removes an achievement gained unfairly, showing the result should not stand", "Because record books can never be changed once a result has been published anywhere", "Because a stripped record automatically increases the performer''s future appearance fees", "Because changing a written record always costs far less than administering any ban"]}'::jsonb, '{"answer": 0, "explain": "Stripping a record removes an achievement that was gained through cheating, so the result no longer stands — record books are updated, and this has nothing to do with fees or cost."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:7e651a7d', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "A young performer is deciding whether to risk using a banned substance. Which sanction is designed to put them off doing so?", "options": ["Free entry into every future competition no matter what the eventual result is", "The threat of a lengthy ban, a fine, and losing any medals won if they are caught", "A guarantee that drugs testing will never take place at their level of competition", "A private meeting where no written record of any offence is ever kept on file"]}'::jsonb, '{"answer": 1, "explain": "Severe, well-known sanctions — a long ban, a fine, losing medals — are exactly what is meant to deter a performer from taking the risk in the first place."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:3727d49e', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "A cyclist banned for two years after a first doping offence tests positive again three years later. Based on how sanctions usually work, what is most likely?", "options": ["The second ban is likely to be equal to or longer than the first, possibly a lifetime ban", "The second offence is ignored completely because the first ban has already been served", "The governing body must reduce any new ban because one has already been served before", "The cyclist instead receives a medal in recognition of admitting to the second failed test"]}'::jsonb, '{"answer": 0, "explain": "Repeat offences are treated more, not less, seriously — a second ban is likely to match or exceed the first, up to a lifetime ban, not be reduced or ignored."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:mcq:a323ccb8', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of publicising the sanctions given to performers caught using PEDs?", "options": ["To help the performer''s existing sponsors quickly design a brand new advertising campaign", "To deter other performers by making the real consequences of being caught widely known", "To increase ticket sales across the venue for that performer''s very next scheduled event", "To give sports journalists something new and unrelated to write about each week"]}'::jsonb, '{"answer": 1, "explain": "Publicising sanctions is a deterrent — it shows every other performer exactly what being caught actually costs, which is the point of making it public."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:0e707453', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "A ban is always exactly the same length, regardless of whether it is a first or repeat offence."}'::jsonb, '{"answer": false, "explain": "Ban length varies with the case — a first offence may carry a set number of years, while repeat offenders can face a lifetime ban."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:3aebeaa4', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "A performer can be fined and banned at the same time for a single PED offence."}'::jsonb, '{"answer": true, "explain": "Sanctions can be combined — a fine punishes financially while a ban stops the performer competing, so both can apply to one offence."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:0793da2c', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "Being stripped of a record means it is removed from the record books as though it had not happened."}'::jsonb, '{"answer": true, "explain": "Stripping removes the achievement entirely — the record is deleted or reallocated, not just noted as suspicious."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:8e1da17b', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "Sanctions exist only to punish the individual performer and have no effect on anyone else."}'::jsonb, '{"answer": false, "explain": "Sanctions are also meant to deter — by making the consequences clear, they aim to put other performers off using PEDs too."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:99fbebf7', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "A performer who is caught using PEDs more than once can receive a lifetime ban."}'::jsonb, '{"answer": true, "explain": "Repeat offences are treated more severely, and a lifetime ban is the toughest sanction available for persistent cheating."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tf:644bbe14', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tf', 'tf', 1, '{"question": "Fines for PED offences are always exactly the same amount, whatever the case involves."}'::jsonb, '{"answer": false, "explain": "Fines vary in amount depending on the case — they are not a single fixed sum applied to every offence."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:learn:b673d81a', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Bans — the headline sanction for PED use", "reading": "<h4>What a sanction is</h4>\n<ul>\n<li>A <strong>sanction</strong> is an official penalty handed out once a performer has been found guilty of using a prohibited substance or method.</li>\n<li>The best-known sanction is a <strong>ban</strong> — the performer cannot train with their squad, enter competitions, or receive funding, for a set period.</li>\n</ul>\n<h4>Bans vary in length</h4>\n<ul>\n<li>A ban is not one fixed punishment — its length changes case by case. A first offence often carries a ban of a <strong>set number of years</strong>, rather than a short suspension.</li>\n<li>A performer caught using PEDs <strong>more than once</strong> can be given a <strong>lifetime ban</strong>, ending their career in that sport completely.</li>\n<li>The exam expects you to know that length reflects seriousness: a longer, or lifetime, ban shows that repeated or serious cheating is treated far more harshly than a single lapse.</li>\n</ul>", "question": "Which statement about bans as a sanction against PED use is correct?", "options": ["A ban always lasts precisely the same length regardless of whether it is a first or repeat offence", "Ban length can vary, and a performer who repeatedly offends can receive a lifetime ban", "Bans can only ever be given to performers who have never previously failed a drugs test", "A ban means a performer must pay a large fixed sum instead of missing any competitions"]}'::jsonb, '{"answer": 1, "explain": "Ban length is not fixed — it varies with the case, and repeat offenders can receive a lifetime ban. A ban is about missing competition, not a payment."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:learn:78545e79', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Fines, and being stripped of medals, titles and records", "reading": "<h4>Fines</h4>\n<ul>\n<li>Alongside a ban, a performer found guilty of using PEDs can be given a <strong>fine</strong> — a sum of money they must pay as part of their punishment.</li>\n<li>Fines vary in amount depending on the case, and can be added on top of a ban rather than replacing one.</li>\n</ul>\n<h4>Being stripped of medals, titles and records</h4>\n<ul>\n<li>A guilty performer can also be <strong>stripped of medals, titles and records</strong> won while using a prohibited substance or method.</li>\n<li>This means a medal is returned or reallocated, a title is taken away, and a record is deleted from the record books, as if the result had never happened.</li>\n<li>This sanction targets a performer''s <strong>reputation and achievements</strong>, not only their money or their ability to compete — for many elite performers, losing a title or record hurts more than a fine.</li>\n</ul>", "question": "What does it mean for a performer to be ''stripped'' of a medal after a PED offence?", "options": ["The medal is cleaned and sent back to the performer in fully restored condition", "The medal, title or record is taken away and the result is removed from the record books", "The performer is instead given a smaller replacement medal made from a cheaper metal", "The performer keeps the medal but must wear it at every single future competition entered"]}'::jsonb, '{"answer": 1, "explain": "Being ''stripped'' means the medal, title or record is formally taken away and removed from the record books — the achievement no longer stands."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:learn:3c07e865', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Why sanctions exist — deterrence as well as punishment", "reading": "<h4>Two jobs, one sanction</h4>\n<ul>\n<li>A sanction does two jobs at once. First, it <strong>punishes</strong> the individual performer who has already broken the rules — through a ban, a fine, or being stripped of what they won.</li>\n<li>Second, it is meant to <strong>deter</strong> — to put other performers off using PEDs in the first place, by making the consequences clear and severe.</li>\n</ul>\n<h4>Building an exam-ready answer</h4>\n<ul>\n<li>Weak answer: <em>\"Cheats get banned.\"</em> That names a sanction but shows no understanding of its purpose.</li>\n<li>Strong answer: <em>\"A lifetime ban deters other performers because it shows repeat cheating ends a career completely, so the risk clearly outweighs any gain.\"</em></li>\n<li>Section C questions often ask you to judge <strong>whether sanctions actually work as a deterrent</strong> — a good answer weighs the size of the punishment against how likely a performer thinks they are to be caught.</li>\n</ul>", "question": "Besides punishing the individual, what is a sanction against PED use also meant to do?", "options": ["Deter other performers from choosing to use prohibited substances themselves", "Guarantee that particular sport will never again see any further doping case", "Reduce how much training a completely clean performer is allowed to do", "Increase the total prize money available to the eventual winning performer"]}'::jsonb, '{"answer": 0, "explain": "A sanction is meant to deter other performers, not just punish the one caught — it cannot guarantee no future case, and it has no effect on clean performers'' training or prize funds."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:misc:c53c9d0d', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A ban is the only sanction a governing body can use against PED use.</p><p><strong>✅ The correct idea:</strong> A ban is only one option. Governing bodies can also fine a performer, and strip them of medals, titles and records won while using a prohibited substance — often combining more than one sanction for a single offence, because each targets something different (time, money, reputation).</p>", "question": "Besides a ban, what else can a governing body use to sanction a PED offence?", "options": ["Nothing else — a ban is always the complete sanction on its own", "A fine, and/or being stripped of medals, titles or records", "A permanent increase in the performer''s future prize money", "A guarantee of a place at the performer''s next major competition"]}'::jsonb, '{"answer": 1, "explain": "Fines and being stripped of medals/titles/records are real, separate sanctions that can sit alongside a ban."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:misc:e6fb6387', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Sanctions only punish the performer who was caught — they don''t affect anyone else''s choices.</p><p><strong>✅ The correct idea:</strong> Sanctions have a second job: deterrence. By making a ban, fine or stripped record public and severe, governing bodies aim to put other performers off using PEDs, because they can see exactly what being caught actually costs.</p>", "question": "What is the second purpose of a sanction, alongside punishing the individual performer?", "options": ["Deterring other performers from choosing to use PEDs themselves", "Making sure the sport receives more media coverage each season", "Ensuring no performer is ever tested for banned substances again", "Guaranteeing the performer a route back into the sport next year"]}'::jsonb, '{"answer": 0, "explain": "Deterrence is the second purpose — showing other performers the real consequences so they choose not to risk using PEDs."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:misc:37e089f1', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once a performer has served their ban, the offence is forgotten and any record they set still stands.</p><p><strong>✅ The correct idea:</strong> Serving a ban does not undo being stripped of a medal, title or record — those stay removed from the record books permanently. And the offence itself is not forgotten: if the same performer is caught again, it counts as a repeat offence and can lead to a lifetime ban.</p>", "question": "After a performer finishes serving a ban, what happens to a record they were stripped of?", "options": ["It is automatically restored back to them once their ban period fully ends", "It stays removed from the record books; serving the ban does not restore it", "It is reassigned permanently to whichever performer finished in second place", "It is kept on hold until the performer''s very next competition begins"]}'::jsonb, '{"answer": 1, "explain": "Being stripped of a record is permanent — finishing a ban does not undo it, and a later offence still counts as a repeat."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tips:a6663b2a', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Sanctions questions are usually short recall, but can be developed into applied points. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one sanction used against PED use\" = write one sanction, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what the sanction involves. \"Describe a ban as a sanction\" = explain what happens to the performer.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why a lifetime ban might be given\" = the sanction <em>plus</em> why (usually a repeat offence).</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; marks in Section B want points applied to the scenario given.</p>", "question": "A question says: ''Identify two sanctions used against PED use [2]''. What is the safest answer?", "options": ["A long paragraph describing only one sanction in detail", "Two sanction names, such as a ban and a fine", "One sanction explained at great length with no second name given", "A list of six different sanctions written out in full"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining only one, or listing six, wastes time and risks marks only being credited for the first two anyway."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tips:cb1e9edd', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the sanction AND its intended effect", "reading": "<p>The single most common way to lose marks here is stopping at the sanction''s name. Build every answer as <strong>sanction → effect → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"A lifetime ban.\"</li>\n<li><strong>✅ full marks:</strong> \"A lifetime ban punishes the performer by ending their career, and deters others because it shows repeat cheating is never worth the risk.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named performer, a named offence). Then you must use a detail <em>from that scenario</em> — such as whether it is a first or repeat offence — not a general example.</p>", "question": "In a Section B scenario question about a named performer''s PED offence, your sanction choice should be based on...", "options": ["absolutely any sanction at all, chosen without reference to the scenario given", "the details given in the scenario, such as whether it is a repeat offence", "the sanction you personally think sounds the most severe", "a sanction used in a completely different named sport"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for linking a sanction to the actual detail in the scenario, such as whether the offence is a first or repeat one."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:tips:8296b107', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where sanctions appear in the exam + sentence starters", "reading": "<p><strong>Where it shows up:</strong> sanctions appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a named performer''s offence, and they feed <strong>Section C</strong> 8-mark discussions about whether current sanctions are effective enough.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the three sanctions together — ban, fine, stripped of medals/titles/records — so you can always recall more than one.</li>\n<li>For every sanction, memorise its <em>intended effect</em> (punish and/or deter) — that link is usually where the mark is.</li>\n<li>Watch for the first-offence vs repeat-offence distinction — it is a great way to justify why one sanction is more severe than another.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One sanction that could be applied here is… because…\"</li>\n<li>\"This sanction is intended to deter other performers by…\"</li>\n<li>\"However, this sanction may not fully stop PED use because…\"</li>\n</ul>", "question": "Why is the first-offence vs repeat-offence distinction a useful point in a longer answer?", "options": ["It fills space without needing to say anything further", "It justifies why one sanction is harsher than another", "It proves that sanctions are never actually applied at all", "It removes the need to name any sanction whatsoever"]}'::jsonb, '{"answer": 1, "explain": "Linking the sanction''s severity to whether it is a first or repeat offence shows deeper understanding — exactly the kind of point that lifts a longer answer."}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:fib:b15029d5', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'fib', 'fib', 1, '{"question": "A performer found guilty of a PED offence can receive a _____, stopping them competing for a period.", "blankOptions": {"B1": ["ban", "deter", "lifetime", "stripped"]}}'::jsonb, '{"blanks": {"B1": "ban"}}'::jsonb),
