('sport-studies:2-5-4-sanctions-against-peds:fib:56a00786', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'fib', 'fib', 1, '{"question": "Sanctions are meant to _____ other performers from choosing to use PEDs in the first place.", "blankOptions": {"B1": ["lifetime", "ban", "fine", "deter"]}}'::jsonb, '{"blanks": {"B1": "deter"}}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:c41a242f', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ban”?", "options": ["The way a severe, well-known sanction is meant to put other performers off using PEDs", "A sanction stopping a performer training or competing for a period, which can extend to a lifetime for repeat offenders", "A performer who has already been sanctioned before and is then caught using PEDs again", "A ban with no end date, usually given for a serious or repeated PED offence"]}'::jsonb, '{"answer": 1, "explain": "“Ban” means: A sanction stopping a performer training or competing for a period, which can extend to a lifetime for repeat offenders"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:58fe6bb2', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fine”?", "options": ["The way a severe, well-known sanction is meant to put other performers off using PEDs", "A performer who has already been sanctioned before and is then caught using PEDs again", "A sum of money a performer must pay as part of their punishment for a PED offence", "Having an achievement gained while using a prohibited substance formally taken away"]}'::jsonb, '{"answer": 2, "explain": "“Fine” means: A sum of money a performer must pay as part of their punishment for a PED offence"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:179cd025', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stripped of a medal, title or record”?", "options": ["A sum of money a performer must pay as part of their punishment for a PED offence", "A sanction stopping a performer training or competing for a period, which can extend to a lifetime for repeat offenders", "Having an achievement gained while using a prohibited substance formally taken away", "A performer who has already been sanctioned before and is then caught using PEDs again"]}'::jsonb, '{"answer": 2, "explain": "“Stripped of a medal, title or record” means: Having an achievement gained while using a prohibited substance formally taken away"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:2586adf9', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lifetime ban”?", "options": ["A sum of money a performer must pay as part of their punishment for a PED offence", "The way a severe, well-known sanction is meant to put other performers off using PEDs", "Having an achievement gained while using a prohibited substance formally taken away", "A ban with no end date, usually given for a serious or repeated PED offence"]}'::jsonb, '{"answer": 3, "explain": "“Lifetime ban” means: A ban with no end date, usually given for a serious or repeated PED offence"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:5f6dc90a', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Deterrent effect”?", "options": ["A sum of money a performer must pay as part of their punishment for a PED offence", "The way a severe, well-known sanction is meant to put other performers off using PEDs", "A performer who has already been sanctioned before and is then caught using PEDs again", "A ban with no end date, usually given for a serious or repeated PED offence"]}'::jsonb, '{"answer": 1, "explain": "“Deterrent effect” means: The way a severe, well-known sanction is meant to put other performers off using PEDs"}'::jsonb),
('sport-studies:2-5-4-sanctions-against-peds:match:03f52f03', 'sport-studies', 'sport-studies:2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Repeat offender”?", "options": ["A performer who has already been sanctioned before and is then caught using PEDs again", "A ban with no end date, usually given for a serious or repeated PED offence", "A sanction stopping a performer training or competing for a period, which can extend to a lifetime for repeat offenders", "A sum of money a performer must pay as part of their punishment for a PED offence"]}'::jsonb, '{"answer": 0, "explain": "“Repeat offender” means: A performer who has already been sanctioned before and is then caught using PEDs again"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:exam:e11b54f9', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best explains why family can play a role in educating a young athlete against future PED use?", "options": ["They shape the athlete''s early attitudes to fairness and honesty, long before formal education begins", "They are legally required to drug-test the athlete before every single training session without exception", "They replace the athlete''s coach as the only source of anti-doping information", "They guarantee the athlete will never be tempted to use a banned substance"], "hint": "Think about when family influence happens compared with formal anti-doping education.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — They shape the athlete''s early attitudes to fairness and honesty, long before formal education begins.</strong></p>\n<ul>\n<li>Family influence attitudes from a young age, before any club or governing body programme starts.</li>\n<li>Family are not testers, and they do not replace a coach — those are different roles entirely.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb)
